                    break;

                case 'church':
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    break;

                case 'report-saved':
                    const { setSavedReports } = reportManager;
                    setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    break;

                case 'report-row':
                    const { reportType } = deletingItem.meta || {};
                    if (reportType) {
                        reconciliationLogic.updateReportData({ transaction: { id: deletingItem.id } } as any, reportType, deletingItem.id);
                    }
                    break;

